VALUES
  ('real-estate-moex-01482', 'real-estate', 'real-estate-moex-104-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '依公平交易法之規定，關於事業結合的敘述，下列何者正確？', '["事業結合行為原則上禁止，例外採取申報主義", "主管機關對於受理事業結合申報案件所為延長受理期間之決定，不得附加條件", "事業自主管機關受理其提出完整申報資料之日起算30日內，不得為結合行為", "事業申報後，經中央主管機關禁止其結合而結合，處新臺幣五萬元以上五千萬元以下罰鍰"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "6f4a35537845", "answer_pdf_sha1": "63f780aa7d6e", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01483', 'real-estate', 'real-estate-moex-104-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '依公平交易法第21條之規定，下列敘述何者錯誤？', '["事業不得在商品上對於商品之製造方法為虛偽不實表示", "事業對在商品廣告上對於商品之用途為引人錯誤之表示時，此商品不得運送", "事業不得以其他使公眾得知之方法，對於商品之使用方法為虛偽不實之表示", "廣告媒體業知曉其刊載之廣告有引人錯誤之虞，仍予刊載，損害賠償責任在廣告主，其無須負連帶損 害賠償責任"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "6f4a35537845", "answer_pdf_sha1": "63f780aa7d6e", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01484', 'real-estate', 'real-estate-moex-104-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '依公平交易法規定，違反獨占或聯合行為之規定，經主管機關限期命其停止、改正其行為或採取必要更 正措施，屆期未停止、改正其行為或未採取必要更正措施，或停止後再為相同違反行為時，處行為人幾 年以下有期徒刑？', '["1年", "2年", "3年", "5年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "6f4a35537845", "answer_pdf_sha1": "63f780aa7d6e", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01485', 'real-estate', 'real-estate-moex-104-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '依消費者保護法規定，直轄市或縣（市）政府對於建商興建預售屋商品出售予消費者所為之行政監督的 敘述，下列何者錯誤？', '["直轄市或縣（市）政府認為建商提供之預售屋有損害消費者生命、身體、健康或財產之虞者，應即進 行調查。於調查完成後，不得公開其經過及結果", "直轄市或縣（市）政府於調查時，對於可為證據之物，得聲請檢察官扣押之", "直轄市或縣（市）政府對於建商提供之商品或服務，經調查認為確有損害消費者生命、身體、健康或 財產，或確有損害之虞者，應命其限期改善、回收或銷燬", "直轄市或縣（市）政府於建商提供之商品或服務，對消費者已發生重大損害或有發生重大損害之虞， 而情況危急時，除命其限期改善、回收或銷燬之處置外，應即在大眾傳播媒體公告企業經營者之名稱、 地址、商品、服務、或為其他必要之處置"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "6f4a35537845", "answer_pdf_sha1": "63f780aa7d6e", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01486', 'real-estate', 'real-estate-moex-104-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '發生消費爭議時，不動產經紀業經營者對於消費者之申訴，依消費者保護法之規定，應於申訴之日起幾 日內妥適處理之？', '["5日", "10日", "15日", "20日"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "6f4a35537845", "answer_pdf_sha1": "63f780aa7d6e", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01487', 'real-estate', 'real-estate-moex-104-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '建商銷售房屋因同一原因事件，致使眾多購屋者受害時，依消費者保護法規定，消費者保護團體得受讓 多少人以上之購屋者的損害賠償請求權後，以自己名義提起訴訟？', '["10人", "20人", "30人", "50人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "6f4a35537845", "answer_pdf_sha1": "63f780aa7d6e", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01488', 'real-estate', 'real-estate-moex-104-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '消費者與不動產經紀業經營者因商品或服務發生消費爭議時，依消費者保護法之規定，關於爭議的解決 方式，下列敘述何者錯誤？', '["消費者得向不動產經紀業經營者、消費者保護團體或消費者服務中心或其分中心申訴", "消費者向", "等對象申訴未能獲得妥適處理時，得向直轄市或縣（市）消費爭議調解委員會申請調解", "調解程序，於直轄市、縣（市）政府或其他適當之處所行之，其程序得公開"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "6f4a35537845", "answer_pdf_sha1": "63f780aa7d6e", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01489', 'real-estate', 'real-estate-moex-104-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '依消費者保護法之規定，關於消費訴訟事件，下列敍述何者錯誤？', '["因不動產經紀業經營者之故意所致之損害，消費者得請求損害額5倍以下之懲罰性賠償金", "因不動產經紀業經營者之過失所致之損害，消費者得請求損害額3倍以下之懲罰性賠償金", "法院為不動產經紀業經營者敗訴之判決時，得依職權宣告減免擔保之假執行", "消費者保護團體以自己之名義提起訴訟時，其標的價額超過新臺幣60萬元者，超過部分免繳裁判費"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "6f4a35537845", "answer_pdf_sha1": "63f780aa7d6e", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01490', 'real-estate', 'real-estate-moex-104-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '依公寓大廈管理條例之規定，公寓大廈之住戶應遵守事項，下列敘述何者正確？', '["於維護、修繕專有部分、約定專用部分或行使其權利時，不得妨害其住戶之安寧、安全及衛生", "他住戶因維護、修繕專有部分、約定專用部分或設置管線，必須進入或使用其專有部分或約定專用部 分時，得拒絕", "管理負責人或管理委員會因維護、修繕共用部分或設置管線，必須進入或使用其專有部分或約定專用 部分時，得拒絕", "於維護、修繕專有部分、約定專用部分或設置管線，必須使用共用部分時，不需經管理負責人或管理 委員會之同意後為之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "6f4a35537845", "answer_pdf_sha1": "63f780aa7d6e", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01491', 'real-estate', 'real-estate-moex-104-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '依公寓大廈管理條例之規定，公寓大廈約定專用部分之修繕、管理、維護，由何人為之，並負擔其費用？', '["管理委員會", "管理負責人", "管理服務人", "約定專用部分之使用人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "6f4a35537845", "answer_pdf_sha1": "63f780aa7d6e", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
